void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("pirate4_1");			link.l1 = StringFromKey("pirate4_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("pirate4_3");			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "2";		break;		case "":			dialog.text = "";			link.l1 = "";			link.l1.go = "";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}